import os
from langchain import LLMChain, PromptTemplate
from langchain.chains import RetrievalQA
from langchain.embeddings import HuggingFaceEmbeddings
from langchain.vectorstores import FAISS
from langchain.llms import OpenAI

# Load company documents into vector database
def load_documents(file_paths):
    embeddings = HuggingFaceEmbeddings()
    documents = []
    for file_path in file_paths:
        with open(file_path, 'r') as file:
            documents.append(file.read())
    vector_store = FAISS.from_texts(documents, embeddings)
    return vector_store

# Create RAG system
def create_rag_system(vector_store):
    llm = OpenAI(api_key=os.getenv('OPENAI_API_KEY'))
    prompt_template = PromptTemplate(
        input_variables=["context", "question"],
        template="Use the following context to answer the question: {context}\nQuestion: {question}"
    )
    chain = LLMChain(llm=llm, prompt=prompt_template)
    rag_system = RetrievalQA(chain=chain, retriever=vector_store.as_retriever())
    return rag_system

# Securely handle user queries
def secure_query_handling(rag_system):
    def query_handler(user_input):
        if not validate_input(user_input):
            raise ValueError("Invalid input")
        context = rag_system.retriever.get_relevant_documents(user_input)
        response = rag_system.run({"context": context, "question": user_input})
        return response
    return query_handler

